__d(function(e,o,n,a,r,t,i){r.exports={app:{name:"GOVDAO",bundleId:"com.govdao.app",version:"0.2.0",environment:"polygon",distribution:{channel:"google-play",pricingModel:"subscription",hostedServices:["notifications","search","ipfs-pinning"]}},wallet:{required:!0,supported:["walletconnect","coinbase-wallet","injected"]},chain:{id:137,name:"polygon",rpcUrl:"https://polygon-mainnet.g.alchemy.com/v2/nTxCkb9NGgPk3FUXMlDsC",blockExplorer:"https://polygonscan.com"},contracts:{memberRegistry:"0xaFBAB7016b1c17A2099De448aC2f74bA563b2Aaa",timelock:"0x72B35C420259a2330adE3293E1fEFd79cf0244E5",governor:"0x85A460c2992f1928612D027d1D860543B00f921f",treasury:"0x707567E47F1a858ca152AB966A6dAE3975143Ee5",emergencyGuardian:"0xe4E518e58fEa19B0C8398833607CD82c3feb342d"},features:{proposalFeed:!0,proposalCreation:!0,voting:!0,treasuryView:!0,pushNotifications:!0,biometricConfirm:!0,fiatOnramp:!1,plan:"free"},services:{metadataBaseUrl:"https://photon-bounce.com/govdao/api/metadata",indexerBaseUrl:"https://photon-bounce.com/govdao/api/indexer",notificationBaseUrl:"https://photon-bounce.com/govdao/api/notifications",mobileFeeds:{proposalsPath:"/mobile/proposals",motionsPath:"/mobile/motions",treasuryPath:"/mobile/treasury",guardianPath:"/mobile/guardian",workspacePath:"/mobile/workspace",membersPath:"/mobile/members"}},support:{website:"https://photon-bounce.com/govdao",email:"lindapots2000@gmail.com",legalName:"PhotonBounce",privacyPolicyUrl:"https://photon-bounce.com/govdao/privacy.html",termsOfServiceUrl:"https://photon-bounce.com/govdao/terms.html"},governance:{mode:"hybrid",offchain:{enabled:!0,provider:"govdao-control-plane",apiBaseUrl:"fixture://govdao",auth:["passkey","wallet-signature"],proposalStorage:"postgres+ipfs",voteStorage:"postgres+merkle-anchoring",voteAnchoringEnabled:!0}},experiences:{primaryModuleId:"dao",modules:[{id:"dao",title:"Governance",kind:"dao",enabled:!0,entryRoute:"/governance",apiBaseUrl:"fixture://govdao",webUrl:"https://photon-bounce.com/govdao/app",requiresAuth:!0},{id:"workspace",title:"Workspace",kind:"documents",enabled:!0,entryRoute:"/workspace",apiBaseUrl:"fixture://govdao",webUrl:"https://photon-bounce.com/govdao/app",requiresAuth:!0}]},release:{android:{applicationId:"com.govdao.app",versionCode:3,track:"internal"},listing:{shortDescription:"On-chain governance for DAOs \u2014 propose, vote, execute on Polygon.",fullDescription:"GOVDAO is a mobile-first governance platform for member-led organizations. Every proposal, vote, and treasury action is secured by five smart contracts deployed on Polygon mainnet \u2014 no backend, no middleman, just transparent on-chain governance in your pocket.\n\n\ud83c\udfdb GOVERNANCE MADE SIMPLE\nCreate and vote on proposals directly from your phone. GOVDAO supports both on-chain votes (finalized on Polygon) and off-chain deliberation, giving your organization the flexibility to deliberate before committing gas.\n\n\ud83d\udcb0 TREASURY TRANSPARENCY\nMonitor your DAO's treasury balance and movement history in real time. Every outgoing transfer is queued through a timelock \u2014 giving members time to react before funds move.\n\n\ud83d\udd14 STAY INFORMED\nGovernance reminders keep you ahead of quorum deadlines and voting windows. Push notifications fire when proposals enter their voting phase or approach execution.\n\n\ud83d\udee1 EMERGENCY GUARDIAN\nSchedule and run guardian drills so your emergency multisig is always battle-ready. When governance needs a circuit breaker, the guardian is there.\n\n\ud83d\udcca ANALYTICS & INSIGHTS (Premium)\nDelegate power maps, proposal risk scoring, sentiment pulse, and participation heatmaps \u2014 the full analytics suite for serious governance operators.\n\n\ud83d\ude80 DEPLOY WIZARD (Premium)\nDeploy the full five-contract governance kernel directly from the app. Configure your DAO's voting delay, quorum, timelock period, and member registry in a guided step-by-step wizard.\n\n\ud83d\udd10 SECURE BY DESIGN\n\u2022 Your wallet never leaves your device \u2014 GOVDAO connects via WalletConnect or Coinbase Wallet\n\u2022 Biometric confirmation for sensitive actions\n\u2022 No personal data collected or stored\n\u2022 Privacy policy: https://photon-bounce.com/govdao/privacy.html\n\n\ud83d\udcf1 FREE & PREMIUM\nCore governance (proposals, voting, treasury, activity) is free. Upgrade to Premium to unlock analytics, guardian drills, member invite with timelock, delegate maps, risk analysis, and the deploy wizard.\n\nBuilt on Polygon \xb7 Open source on GitHub \xb7 Coming to Google Play",category:"business"}}}},309,[]);
